class Muxiveo < Formula
  desc "GUI video workflow tool for remuxing, encoding, Dolby Vision and HDR10+"
  homepage "https://github.com/Hydro74000/muxiveo"
  version "3.0.0"
  license "MIT"

  on_linux do
    url "https://github.com/Hydro74000/muxiveo/releases/download/v3.0.0/Muxiveo-x86_64_allinc-3.0.0.AppImage"
    sha256 "f6d34f342997b6929f6ddb57240a541b06352a79f2de9efe8664159bb0355c2b"
  end

  on_macos do
    url "https://github.com/Hydro74000/muxiveo/releases/download/v3.0.0/Muxiveo-3.0.0-homebrew-macos.tar.gz"
    sha256 "37ef49e87c349567a8ea738c612d68a557836a6884ea8952d477c12ea141a8b3"

    depends_on "ffmpeg"
    depends_on "mediainfo"

    resource "dovi_tool" do
      url "https://github.com/quietvoid/dovi_tool/releases/download/2.3.2/dovi_tool-2.3.2-universal-macOS.zip"
      sha256 "a79653695b29fa61ce46e855baf9bcd2f56628b66ab8266cf87a587914829da7"
    end

    resource "hdr10plus_tool" do
      url "https://github.com/quietvoid/hdr10plus_tool/releases/download/1.7.2/hdr10plus_tool-1.7.2-universal-macOS.zip"
      sha256 "d76977ed2ea90f8d6bce9035e37ea9dbffcead4725ceb1acf455c25d8658ff28"
    end
  end

  def install_setup_brew_helper
    (libexec/"setup_brew.py").write <<~PY
      #!/usr/bin/env python3
      """
      Muxiveo Homebrew post-install helper.

      This script manages user-scoped desktop integration that does not belong inside
      the Homebrew prefix:
        - Linux desktop shortcut in ~/.local/share/applications
        - Linux icon in <prefix>/share/icons/hicolor/256x256/apps
        - macOS app link in ~/Applications
        - desktop database refresh for KDE/GNOME when available
      """

      from __future__ import annotations

      import argparse
      import base64
      import os
      import shutil
      import subprocess
      import tempfile
      import traceback
      from pathlib import Path


      ICON_PNG_BASE64 = ""
      DESKTOP_MIME_TYPES = "audio/aac;audio/flac;audio/mp4;audio/ogg;audio/opus;audio/vnd.dts;audio/vnd.dts.hd;audio/x-m4a;audio/x-matroska;audio/x-ms-wma;audio/x-wav;audio/x-wavpack;application/x-subrip;application/x-matroska;application/x-mpegURL;application/x-ssa;application/x-ass;text/plain;text/vtt;text/x-ass;text/x-ssa;video/mp4;video/mpeg;video/quicktime;video/webm;video/x-flv;video/x-matroska;video/x-msvideo;video/x-ms-wmv;video/x-m2ts;video/x-mpeg;video/x-h264;video/x-h265;video/x-av1;video/x-vc1;"
      APP_NAME = "Muxiveo"


      def _state_log_path() -> Path:
          state_home = Path(os.environ.get("XDG_STATE_HOME", Path.home() / ".local" / "state"))
          return state_home / APP_NAME / "setup_brew.log"


      def _log(message: str) -> None:
          log_path = _state_log_path()
          log_path.parent.mkdir(parents=True, exist_ok=True)
          with log_path.open("a", encoding="utf-8") as handle:
              handle.write(f"{message}\n")


      def _safe_log(message: str) -> None:
          try:
              _log(message)
              return
          except OSError:
              pass

          fallback = Path(tempfile.gettempdir()) / f"{APP_NAME}-setup_brew.log"
          try:
              with fallback.open("a", encoding="utf-8") as handle:
                  handle.write(f"{message}\n")
          except OSError:
              pass


      def _user_data_home() -> Path:
          return Path(os.environ.get("XDG_DATA_HOME", Path.home() / ".local" / "share"))


      def _write_text(path: Path, content: str) -> None:
          path.parent.mkdir(parents=True, exist_ok=True)
          path.write_text(content, encoding="utf-8")


      def _write_binary(path: Path, payload: bytes) -> None:
          path.parent.mkdir(parents=True, exist_ok=True)
          path.write_bytes(payload)


      def _linux_desktop_file(opt_bin: Path) -> str:
          return (
              "[Desktop Entry]\n"
              "Name=Muxiveo\n"
              "Comment=MKV/MP4 workflow - DoVi, HDR10+, encoding\n"
              f"Exec={opt_bin / 'muxiveo'} %F\n"
              f"TryExec={opt_bin / 'muxiveo'}\n"
              "Icon=Muxiveo\n"
              "Type=Application\n"
              "Categories=AudioVideo;Video;\n"
              f"MimeType={DESKTOP_MIME_TYPES}\n"
              "Keywords=video;encode;remux;hdr;dolby vision;dovi;media;\n"
              "Terminal=false\n"
              "StartupNotify=true\n"
              "StartupWMClass=Muxiveo\n"
          )


      def install_linux_shortcut(opt_bin: Path, opt_share: Path) -> None:
          icon_dir = opt_share / "icons" / "hicolor" / "256x256" / "apps"
          icon_path = icon_dir / "Muxiveo.png"
          icon_bytes = base64.b64decode(ICON_PNG_BASE64)
          _write_binary(icon_path, icon_bytes)

          data_home = _user_data_home()
          user_icon = data_home / "icons" / "hicolor" / "256x256" / "apps" / "Muxiveo.png"
          _write_binary(user_icon, icon_bytes)

          desktop_file = data_home / "applications" / "Muxiveo.desktop"
          _write_text(desktop_file, _linux_desktop_file(opt_bin))
          _log(f"desktop-file={desktop_file}")
          _log(f"user-icon={user_icon}")
          _log(f"prefix-icon={icon_path}")

          validator = shutil.which("desktop-file-validate")
          if validator:
              result = subprocess.run([validator, str(desktop_file)], check=False, capture_output=True, text=True)
              _log(f"desktop-file-validate rc={result.returncode}")
              if result.stdout:
                  _log(result.stdout.strip())
              if result.stderr:
                  _log(result.stderr.strip())

          for command in (
              "update-desktop-database",
              "gtk-update-icon-cache",
              "xdg-desktop-menu",
              "kbuildsycoca6",
              "kbuildsycoca5",
          ):
              executable = shutil.which(command)
              if not executable:
                  continue
              args = [executable]
              if command == "update-desktop-database":
                  args.append(str(desktop_file.parent))
              elif command == "gtk-update-icon-cache":
                  args.extend(["-q", "-t", str((data_home / "icons" / "hicolor"))])
              elif command == "xdg-desktop-menu":
                  args.append("forceupdate")
              result = subprocess.run(args, check=False, capture_output=True, text=True)
              _log(f"{command} rc={result.returncode}")
              if result.stdout:
                  _log(result.stdout.strip())
              if result.stderr:
                  _log(result.stderr.strip())


      def install_macos_link(opt_prefix: Path) -> None:
          apps_dir = Path.home() / "Applications"
          apps_dir.mkdir(parents=True, exist_ok=True)
          app_link = apps_dir / "Muxiveo.app"
          app_target = opt_prefix / "Muxiveo.app"
          if app_link.is_symlink() or app_link.exists():
              return
          try:
              app_link.symlink_to(app_target)
          except OSError:
              return


      def cleanup_shortcuts() -> None:
          data_home = _user_data_home()
          desktop_file = data_home / "applications" / "Muxiveo.desktop"
          user_icon = data_home / "icons" / "hicolor" / "256x256" / "apps" / "Muxiveo.png"
          app_link = Path.home() / "Applications" / "Muxiveo.app"
          log_path = _state_log_path()
          for path in (desktop_file, user_icon, app_link, log_path):
              try:
                  path.unlink()
              except FileNotFoundError:
                  continue
              except OSError:
                  continue


      def parse_args() -> argparse.Namespace:
          parser = argparse.ArgumentParser(description="Muxiveo Homebrew setup helper.")
          subparsers = parser.add_subparsers(dest="command", required=True)

          post_install = subparsers.add_parser("post-install")
          post_install.add_argument("--platform", choices=("linux", "macos"), required=True)
          post_install.add_argument("--opt-bin", required=True)
          post_install.add_argument("--opt-share", required=True)
          post_install.add_argument("--opt-prefix", required=True)

          subparsers.add_parser("cleanup")
          return parser.parse_args()


      def main() -> int:
          try:
              args = parse_args()
              if args.command == "cleanup":
                  cleanup_shortcuts()
                  return 0

              opt_bin = Path(args.opt_bin)
              opt_share = Path(args.opt_share)
              opt_prefix = Path(args.opt_prefix)

              if args.platform == "linux":
                  install_linux_shortcut(opt_bin, opt_share)
              else:
                  install_macos_link(opt_prefix)
          except Exception as exc:
              _safe_log(f"fatal-error={exc!r}")
              _safe_log(traceback.format_exc().rstrip())
          return 0


      if __name__ == "__main__":
          raise SystemExit(main())
    PY
    chmod 0755, libexec/"setup_brew.py"
  end

  def install_uninstall_shortcuts_script
    (libexec/"muxiveo-uninstall-shortcuts").write <<~EOS
      #!/bin/bash
      set -euo pipefail
      PYTHON_BIN="$(command -v python3 || command -v python || true)"
      if [ -z "${PYTHON_BIN}" ]; then
        echo "python3 is required to clean Muxiveo shortcuts" >&2
        exit 1
      fi
      exec "${PYTHON_BIN}" "#{opt_libexec}/setup_brew.py" cleanup
    EOS
    chmod 0755, libexec/"muxiveo-uninstall-shortcuts"
    bin.install_symlink libexec/"muxiveo-uninstall-shortcuts"
  end

  def run_setup_brew(*args)
    python = which("python3") || which("python")
    odie "python3 is required for Muxiveo Homebrew integration" if python.nil?

    system python, libexec/"setup_brew.py", *args.map(&:to_s)
  end

  def install
    if OS.mac?
      prefix.install "Muxiveo.app"
      (libexec/"tools").mkpath
      install_setup_brew_helper
      install_uninstall_shortcuts_script

      resource("dovi_tool").stage do
        libexec.install Dir["**/dovi_tool"].first => "tools/dovi_tool"
      end

      resource("hdr10plus_tool").stage do
        libexec.install Dir["**/hdr10plus_tool"].first => "tools/hdr10plus_tool"
      end

      chmod 0755, libexec/"tools/dovi_tool"
      chmod 0755, libexec/"tools/hdr10plus_tool"

      (libexec/"muxiveo").write <<~EOS
        #!/bin/bash
        set -euo pipefail
        CONFIG_DIR="${XDG_CONFIG_HOME:-$HOME/.config}/muxiveo"
        CONFIG_FILE="${CONFIG_DIR}/config.ini"
        mkdir -p "${CONFIG_DIR}"
        if [ ! -f "${CONFIG_FILE}" ]; then
          cat > "${CONFIG_FILE}" <<'CFG'
# Muxiveo - configuration locale
# Fichier cree par le wrapper Homebrew pour eviter le setup interactif.
CFG
        fi
        export PATH="#{opt_libexec}/tools:#{HOMEBREW_PREFIX}/bin:$PATH"
        exec "#{opt_prefix}/Muxiveo.app/Contents/MacOS/muxiveo" "$@"
      EOS
      chmod 0755, libexec/"muxiveo"
      bin.install_symlink libexec/"muxiveo"
    else
      libexec.install Dir["*.AppImage"].first => "Muxiveo.AppImage"
      chmod 0755, libexec/"Muxiveo.AppImage"
      install_setup_brew_helper
      install_uninstall_shortcuts_script

      (libexec/"muxiveo").write <<~EOS
        #!/bin/bash
        set -euo pipefail
        CONFIG_DIR="${XDG_CONFIG_HOME:-$HOME/.config}/muxiveo"
        CONFIG_FILE="${CONFIG_DIR}/config.ini"
        mkdir -p "${CONFIG_DIR}"
        if [ ! -f "${CONFIG_FILE}" ]; then
          cat > "${CONFIG_FILE}" <<'CFG'
# Muxiveo - configuration locale
# Fichier cree par le wrapper Homebrew.
CFG
        fi
        if [ ! -e /dev/fuse ]; then
          export APPIMAGE_EXTRACT_AND_RUN=1
        fi
        PYTHON_BIN="$(command -v python3 || command -v python || true)"
        if [ -n "${PYTHON_BIN}" ]; then
          "${PYTHON_BIN}" "#{opt_libexec}/setup_brew.py" post-install --platform linux --opt-bin "#{opt_bin}" --opt-share "#{opt_share}" --opt-prefix "#{opt_prefix}" >/dev/null 2>&1 || true
        fi
        exec "#{opt_libexec}/Muxiveo.AppImage" "$@"
      EOS
      chmod 0755, libexec/"muxiveo"
      bin.install_symlink libexec/"muxiveo"
    end
  end

  def post_install
    if OS.mac?
      run_setup_brew("post-install", "--platform", "macos", "--opt-bin", opt_bin, "--opt-share", opt_share, "--opt-prefix", opt_prefix)
    else
      run_setup_brew("post-install", "--platform", "linux", "--opt-bin", opt_bin, "--opt-share", opt_share, "--opt-prefix", opt_prefix)
    end
  end

  def caveats
    <<~EOS
      User session shortcuts are installed outside the Homebrew prefix.
      If the desktop shortcut does not appear immediately on Linux, run:
        brew postinstall Muxiveo
      Diagnostic log:
        ~/.local/state/Muxiveo/setup_brew.log
      Before `brew uninstall Muxiveo`, run:
        muxiveo-uninstall-shortcuts
    EOS
  end

  test do
    if OS.mac?
      assert_predicate prefix/"Muxiveo.app", :exist?
      assert_predicate bin/"muxiveo", :exist?
    else
      assert_predicate libexec/"Muxiveo.AppImage", :exist?
      assert_predicate bin/"muxiveo", :exist?
    end
  end
end
